section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/us-uk-eu-compliance-matrix.json",
  "type": "object",
  "required": [
    "business_entity",
    "review_period",
    "jurisdictions",
    "contract_templates",
    "tax_status",
    "ai_act_features",
    "counsel_signoff"
  ],
  "properties": {
    "business_entity": {
      "type": "string",
      "description": "string"
    },
    "review_period": {
      "type": "string",
      "description": "string (YYYY-Q#)"
    },
    "jurisdictions": {
      "type": "array",
      "description": "array (each {code, customer_count, revenue, applicable_laws, lawful_basis_per_activity})"
    },
    "contract_templates": {
      "type": "object",
      "description": "object {buyer_type: template_path}"
    },
    "tax_status": {
      "type": "array",
      "description": "array (each {jurisdiction, threshold, current_volume, registered, action})"
    },
    "ai_act_features": {
      "type": "array",
      "description": "array (each {feature, risk_level, conformity_assessment, registration})"
    },
    "counsel_signoff": {
      "type": "object",
      "description": "object {name, date, scope}"
    }
  }
}

example.code:
{
  "business_entity": "Acme LLC (Delaware)",
  "review_period": "2026-Q2",
  "jurisdictions": [
    {
      "code": "US-CA",
      "customer_count": 120,
      "revenue": 80000,
      "applicable_laws": [
        "CCPA",
        "CPRA"
      ],
      "lawful_basis_per_activity": {
        "marketing": "consent"
      }
    }
  ],
  "contract_templates": {
    "b2b_enterprise": "templates/dpa-scc.md",
    "b2b_small": "templates/dpa.md",
    "b2c": "templates/consumer-terms.md"
  },
  "tax_status": [
    {
      "jurisdiction": "US-CA",
      "threshold": 500000,
      "current_volume": 80000,
      "registered": false,
      "action": "monitor"
    }
  ],
  "ai_act_features": [
    {
      "feature": "AI summarisation",
      "risk_level": "limited",
      "conformity_assessment": false,
      "registration": false
    }
  ],
  "counsel_signoff": {
    "name": "Doe Privacy Counsel",
    "date": "2026-05-15",
    "scope": "EU + UK + US-CA"
  }
}
